/* ═══════════════════════════════════════════
   SIHYEON PLAY OS - ABC PHONICS TRANSFORM 
   (글자 이미지 -> 사물 이미지 완벽 변신 버전)
═══════════════════════════════════════════ */

(function () {
  const GAME_KEY = 'abcPhonics';
  const STYLE_ID = 'sihyeon-abc-phonics-style';

  // 아빠가 만든 파일명에 맞춰서 경로를 설정했어요!
  const ABC_DATA = [
    { 
      letter: 'A', phonics: '애, 애', word: 'Apple', color: '#FF3B3B',
      letterImg: 'assets/games/abc-phonics/steps/a.jpg', 
      objectImg: 'assets/games/abc-phonics/steps/apple.jpg' 
    },
    { 
      letter: 'B', phonics: '브, 브', word: 'Ball', color: '#1E90FF',
      letterImg: 'assets/games/abc-phonics/steps/b.jpg', 
      objectImg: 'assets/games/abc-phonics/steps/ball.jpg' 
    },
    { 
      letter: 'C', phonics: '크, 크', word: 'Car', color: '#FFC107',
      letterImg: 'assets/games/abc-phonics/steps/c.jpg', 
      objectImg: 'assets/games/abc-phonics/steps/car.jpg' 
    }
  ];

  const state = {
    container: null, options: {}, currentIndex: 0,
    isTransforming: false, destroyed: false
  };

  function injectStyle() {
    if (document.getElementById(STYLE_ID)) return;
    const style = document.createElement('style');
    style.id = STYLE_ID;
    style.innerHTML = `
      .abc-root {
        position: relative; width: 100%; height: 100%;
        transition: background 0.5s ease, opacity 0.3s ease;
        overflow: hidden; display: flex; flex-direction: column;
        align-items: center; justify-content: space-around;
        padding: 40px 20px; box-sizing: border-box;
        font-family: 'Jua', sans-serif;
        background: white;
      }
      .abc-progress-bar {
        position: absolute; top: 30px; width: 100%;
        display: flex; gap: 15px; justify-content: center; z-index: 5;
      }
      .abc-progress-dot {
        width: 20px; height: 20px; border-radius: 50%; background-color: #ddd;
        transition: all 0.4s;
      }
      .abc-center-box {
        position: relative; z-index: 10; flex: 1;
        display: flex; flex-direction: column; align-items: center; justify-content: center;
        min-width: 280px; min-height: 280px; cursor: pointer;
        animation: abcFloat 3s ease-in-out infinite;
      }
      @keyframes abcFloat {
        0%, 100% { transform: translateY(0px); }
        50% { transform: translateY(-20px); }
      }
      /* 이미지 스타일: 크고 둥글게 */
      .abc-display-img {
        width: clamp(250px, 60vw, 400px);
        height: auto;
        border-radius: 40px;
        box-shadow: 0 15px 35px rgba(0,0,0,0.15);
        transition: all 0.5s cubic-bezier(0.34, 1.56, 0.64, 1);
        border: 8px solid white;
      }
      .abc-transformed img {
        animation: abcPopIn 0.8s cubic-bezier(0.34, 1.56, 0.64, 1) forwards;
      }
      @keyframes abcPopIn {
        0% { transform: scale(0.5) rotate(-5deg); opacity: 0; }
        100% { transform: scale(1) rotate(0deg); opacity: 1; }
      }
      .abc-particle {
        position: absolute; width: 20px; height: 20px; border-radius: 50%;
        pointer-events: none; z-index: 20; animation: abcExplode ease-out forwards;
      }
      @keyframes abcExplode {
        0% { transform: translate(0, 0) scale(1); opacity: 1; }
        100% { transform: translate(var(--tx), var(--ty)) scale(0); opacity: 0; }
      }
      .abc-word-label {
        font-size: clamp(50px, 12vw, 80px); color: #333; font-weight: bold;
        margin-top: 20px; opacity: 0; text-shadow: 2px 2px 10px rgba(255,255,255,0.8);
      }
      .abc-word-label.show { animation: fadeInUp 0.6s forwards; }
      @keyframes fadeInUp { from { opacity: 0; transform: translateY(20px); } to { opacity: 1; transform: translateY(0); } }
      .abc-touch-hint {
        font-size: 32px; color: #666; opacity: 0; background: rgba(255,255,255,0.8);
        padding: 10px 40px; border-radius: 50px; animation: pulse 1.5s infinite alternate;
      }
      @keyframes pulse { from { opacity: 0.4; } to { opacity: 1; } }
    `;
    document.head.appendChild(style);
  }

  function createExplosion(x, y, color) {
    const colors = [color, '#FFF59D', '#FFD700', '#FF69B4', '#00D4FF'];
    for (let i = 0; i < 25; i++) {
      const p = document.createElement('div');
      p.className = 'abc-particle';
      p.style.backgroundColor = colors[i % colors.length];
      const angle = Math.random() * Math.PI * 2;
      const dist = 150 + Math.random() * 200;
      p.style.setProperty('--tx', `${Math.cos(angle) * dist}px`);
      p.style.setProperty('--ty', `${Math.sin(angle) * dist}px`);
      p.style.left = `${x}px`; p.style.top = `${y}px`;
      state.container.querySelector('.abc-root').appendChild(p);
      setTimeout(() => p.remove(), 1000);
    }
  }

  function speak(text, rate = 0.8) {
    if (typeof speechSynthesis !== 'undefined') {
      speechSynthesis.cancel();
      const msg = new SpeechSynthesisUtterance(text);
      msg.lang = 'en-US'; msg.rate = rate;
      speechSynthesis.speak(msg);
    }
  }

  function renderScene() {
    if (state.destroyed) return;
    const data = ABC_DATA[state.currentIndex];
    const root = state.container.querySelector('.abc-root');
    root.style.background = `linear-gradient(135deg, #ffffff 0%, ${data.color}22 100%)`;

    const progressHTML = ABC_DATA.map((d, idx) => `
      <div class="abc-progress-dot" style="${idx <= state.currentIndex ? `background-color:${d.color};transform:scale(1.3);` : ''}"></div>
    `).join('');

    root.innerHTML = `
      <div class="abc-progress-bar">${progressHTML}</div>
      <div class="abc-center-box" id="abc-main-btn">
        <div class="abc-display-container">
          <img src="${data.letterImg}" class="abc-display-img" id="main-img" alt="letter">
        </div>
        <div class="abc-word-label">${data.word}</div>
      </div>
      <div class="abc-touch-hint" id="abc-hint">👆 다음</div>
    `;

    const mainBtn = root.querySelector('#abc-main-btn');
    const mainImg = root.querySelector('#main-img');
    const hint = root.querySelector('#abc-hint');

    mainBtn.addEventListener('click', () => {
      if (state.isTransforming) { nextRound(); return; }
      state.isTransforming = true;

      // 1. 소리 출력
      speak(data.phonics);

      // 2. 폭발 효과
      const rect = mainImg.getBoundingClientRect();
      createExplosion(rect.left + rect.width / 2, rect.top + rect.height / 2, data.color);

      // 3. 이미지 교체 (사물 이미지로!)
      mainImg.src = data.objectImg;
      mainBtn.classList.add('abc-transformed');

      // 4. 단어 라벨 등장
      setTimeout(() => {
        if (state.destroyed) return;
        root.querySelector('.abc-word-label').classList.add('show');
        speak(data.word + "!", 0.9);
        if (state.options.fireConfetti) state.options.fireConfetti();
      }, 700);

      // 5. 다음 안내
      setTimeout(() => {
        if (state.destroyed) return;
        hint.style.opacity = '1';
        root.addEventListener('click', nextRound, { once: true });
      }, 2500);
    });
  }

  function nextRound() {
    if (state.destroyed) return;
    const root = state.container.querySelector('.abc-root');
    root.style.opacity = '0';
    setTimeout(() => {
      state.currentIndex++;
      if (state.currentIndex >= ABC_DATA.length) {
        speak("Wonderful! 시현이 최고!");
        if (state.options.closeToParkHome) state.options.closeToParkHome();
        return;
      }
      state.isTransforming = false;
      root.style.opacity = '1';
      renderScene();
    }, 400);
  }

  function render(container, options = {}) {
    destroy(); injectStyle();
    state.container = container; state.options = options;
    state.destroyed = false; state.currentIndex = 0; state.isTransforming = false;
    container.innerHTML = `<div class="abc-root"></div>`;
    renderScene();
    setTimeout(() => speak("Touch the letter!"), 500);
  }

  function destroy() {
    state.destroyed = true;
    if (state.container) state.container.innerHTML = '';
    if (typeof speechSynthesis !== 'undefined') speechSynthesis.cancel();
  }

  window.SihyeonGames = window.SihyeonGames || {};
  window.SihyeonGames.abcPhonics = { id: GAME_KEY, render, destroy };
})();
